const gallery = document.getElementById('gallery');

function renderCards(dataToRender) {
    gallery.innerHTML = ''; 
    dataToRender.forEach(item => {
        const cardHTML = `
            <div class="card-wrapper" style="border-bottom: 1px solid #eee; padding: 25px 0; width: 100%; max-width: 800px; margin: 0 auto;">
                <a href="${item.link}" target="_blank" class="card" style="text-decoration: none; color: #333; display: flex; align-items: center; justify-content: center;">
                    <span class="date" style="color: #bbb; margin-right: 30px; font-size: 0.9rem;">${item.date.split(' ')[0]}</span>
                    <span class="title" style="font-size: 1.1rem;">${item.title}</span>
                </a>
                <div class="img-preview" style="display: flex; justify-content: center; gap: 10px; margin-top: 15px;">
                    ${item.images.slice(0, 3).map(img => `<img src="${img}" style="height: 80px; border-radius: 4px; opacity: 0.9; object-fit: cover;">`).join('')}
                </div>
            </div>
        `;
        gallery.innerHTML += cardHTML;
    });
}

renderCards(archiveData);

function filterCards(year) {
    const filteredData = (year === '全部') ? archiveData : archiveData.filter(i => i.date.startsWith(year));
    renderCards(filteredData);
}
